func chequeStatusOptions() []models.ChequeStatus {
	return []models.ChequeStatus{models.ChequeStatusDraft, models.ChequeStatusPrinted, models.ChequeStatusVoided}
}

func chequeStatusLabel(status models.ChequeStatus) string {
	switch status {
	case models.ChequeStatusDraft:
		return "Draft"
	case models.ChequeStatusPrinted:
		return "Printed"
	case models.ChequeStatusVoided:
		return "Voided"
	default:
		return string(status)
	}
}

func chequeStatusBadgeClass(status models.ChequeStatus) string {
	base := "inline-block rounded px-2 py-0.5 text-small font-medium "
	switch status {
	case models.ChequeStatusPrinted:
		return base + "bg-success-soft text-success-hover border border-success-border"
	case models.ChequeStatusVoided:
		return base + "bg-background text-text-muted2 border border-border line-through"
	default:
		return base + "bg-warning-soft text-warning border border-warning-soft"
	}
}

func chequeDisplayNumber(cheque models.Cheque) string {
	if cheque.ChequeNumber != "" {
		return cheque.ChequeNumber
	}
	return "Draft " + Uitoa(cheque.ID)
}

func chequeBankAccountLabel(account models.ChequeBankAccount) string {
	if account.BankName != "" {
		return account.Label + " - " + account.BankName
	}
	if account.LedgerAccount != nil {
		return account.Label + " - " + account.LedgerAccount.Code
	}
	return account.Label
}

func chequeLedgerAccountLabel(account models.Account) string {
	if account.Code != "" {
		return account.Code + " - " + account.Name
	}
	return account.Name
}

func chequeCanMarkPrinted(status models.ChequeStatus) bool {
	return status == models.ChequeStatusDraft
}

func chequeCanVoid(status models.ChequeStatus) bool {
	return status == models.ChequeStatusDraft || status == models.ChequeStatusPrinted
}

